693	\subsection{The short-complex carrier}
694	
695	\begin{definition}[Short complex of free $\ModuleCat\,k$-sheaves (iter-019)]
696	  \label{def:Scheme_HModule_prime_shortComplex}
697	  \lean{AlgebraicGeometry.Scheme.HModule'_shortComplex}
698	  \uses{def:Scheme_ModuleCat_free_isLeftAdjoint, lem:Scheme_HModule_prime_isPushoutModuleCatFreeSheaf}
699	  In the setting of Lemma~\ref{lem:Scheme_HModule_prime_isPushoutModuleCatFreeSheaf}, define the short complex of $\Sheaf\,J\,(\ModuleCat\,k)$:
700	  \[
701	    (\presheafToSheaf\,J\,\_)\,(\yoneda\,S.X_1 \circ \ModuleCat.\free\,k)
702	    \xrightarrow{\;f\;}
703	    (\presheafToSheaf\,J\,\_)\,(\yoneda\,S.X_2 \circ \ModuleCat.\free\,k) \boxplus (\presheafToSheaf\,J\,\_)\,(\yoneda\,S.X_3 \circ \ModuleCat.\free\,k)
704	    \xrightarrow{\;g\;}
705	    (\presheafToSheaf\,J\,\_)\,(\yoneda\,S.X_4 \circ \ModuleCat.\free\,k)
706	  \]
707	  where $f$ is the biproduct lift of the pair $(\presheafToSheaf\,(\mathrm{whiskerRight}\,(\yoneda.\mathrm{map}\,S.f_{1,2})), -\presheafToSheaf\,(\mathrm{whiskerRight}\,(\yoneda.\mathrm{map}\,S.f_{1,3})))$ and $g$ is the biproduct desc of the pair $(\presheafToSheaf\,(\mathrm{whiskerRight}\,(\yoneda.\mathrm{map}\,S.f_{2,4})), \presheafToSheaf\,(\mathrm{whiskerRight}\,(\yoneda.\mathrm{map}\,S.f_{3,4})))$. The composition-zero relation $f \circ g = 0$ follows from the cokernel-cofork condition of the pushout in Lemma~\ref{lem:Scheme_HModule_prime_isPushoutModuleCatFreeSheaf}.
708	\end{definition}
709	
710	\begin{proof}
711	  \uses{lem:Scheme_HModule_prime_isPushoutModuleCatFreeSheaf}
712	  Direct mirror of Mathlib's $\mathtt{GrothendieckTopology.MayerVietorisSquare.shortComplex}$ (\texttt{MayerVietorisSquare.lean} L234--249) for the $\ModuleCat\,k$ flavor with $\AddCommGrpCat.\free \rightarrow \ModuleCat.\free\,k$. The five $\mathrm{Type}$-valued fields ($X_1, X_2, X_3, f, g$) are filled inline as term-mode constructions; the $\Prop$-valued $\mathtt{zero}$ field follows from the cokernel-cofork condition of the pushout square. Body for the $\mathtt{zero}$ field:
713	  \begin{lstlisting}
714	  (S.map (yoneda ⋙ (Functor.whiskeringRight _ _ _).obj (ModuleCat.free k) ⋙
715	      presheafToSheaf J _)).cokernelCofork.condition
716	  \end{lstlisting}
717	  The \lstinline{@[simps]} attribute generates field-projection simp lemmas (\lstinline{HModule'_shortComplex_X₁}, \lstinline{..._X₂}, \lstinline{..._X₃}, \lstinline{..._f}, \lstinline{..._g}) consumed by the iter-020+ $\mathtt{Mono}/\mathtt{Epi}/\mathtt{Exact}/\mathtt{ShortExact}$ instance proofs and the iter-022+ $\delta$ definition. Plan-agent \texttt{lean\_run\_code} probe (iter-019) confirms the body typechecks end-to-end, kernel-only axioms.
718	\end{proof}
